import Foundation

let questions3: [QuizQuestion] = [
    // PROFETAS (181-340)
    QuizQuestion(id:181, question:"Qual profeta foi engolido por um grande peixe?", options:["Elias","Jonas","Ezequiel","Jeremias"], correctIndex:1, explanation:"Jonas fugiu do chamado de Deus e foi engolido por um grande peixe. Dentro por 3 dias, orou e arrependeu-se; então foi cuspido na praia.", reference:"Jonas 1:17; 2:10", category:.profetas, propheticMeaning:"Jesus usou Jonas como sinal de sua morte e ressurreição: 'Assim como Jonas ficou três dias e três noites no ventre do grande peixe, assim o Filho do Homem ficará três dias e três noites no coração da terra' (Mt 12:40)."),
    QuizQuestion(id:182, question:"Qual profeta foi levado ao céu em um carro de fogo?", options:["Eliseu","Elias","Daniel","Isaías"], correctIndex:1, explanation:"Elias foi arrebatado ao céu em um carro de fogo enquanto caminhava com Eliseu, que recebeu porção dupla de seu espírito.", reference:"2 Reis 2:11", category:.profetas, propheticMeaning:"Elias sendo arrebatado sem morrer é tipo do arrebatamento da Igreja descrito em 1 Tessalonicenses 4:17. Elias reaparece na Transfiguração (Mt 17:3) e em Apocalipse 11 como uma das duas testemunhas."),
    QuizQuestion(id:183, question:"Qual mar Moisés dividiu para o povo escapar do Egito?", options:["Rio Nilo","Rio Jordão","Mar Vermelho","Rio Eufrates"], correctIndex:2, explanation:"Deus usou Moisés para dividir o Mar Vermelho, permitindo que os israelitas atravessassem em seco enquanto o exército do faraó foi destruído pelas águas.", reference:"Êxodo 14:21-22", category:.profetas, propheticMeaning:"Paulo ensina que a travessia do Mar Vermelho é tipo do batismo (1 Co 10:2): Israel 'foi batizado em Moisés' nas águas. Cristo é o novo Moisés que nos liberta da escravidão do pecado (Egito) e nos conduz à Terra Prometida."),
    QuizQuestion(id:184, question:"Qual alimento Deus enviou para alimentar Israel no deserto?", options:["Pão de trigo","Maná e codornizes","Mel e leite","Frutas e grãos"], correctIndex:1, explanation:"Deus enviou maná (pão do céu) todas as manhãs e codornizes à tarde para alimentar os israelitas durante os 40 anos no deserto.", reference:"Êxodo 16:14-15", category:.profetas, propheticMeaning:"O maná do deserto é tipo de Cristo, o verdadeiro Pão que desceu do céu (Jo 6:32-35). Assim como o maná sustentou Israel no deserto, Jesus sustenta seu povo na jornada da vida até a Terra Prometida da eternidade."),
    QuizQuestion(id:185, question:"Quantas pragas Deus enviou sobre o Egito?", options:["7","9","10","12"], correctIndex:2, explanation:"Deus enviou dez pragas sobre o Egito para forçar o faraó a libertar Israel: sangue, rãs, piolhos, moscas, morte do gado, úlceras, granizo, gafanhotos, trevas e morte dos primogênitos.", reference:"Êxodo 7-12", category:.profetas, propheticMeaning:"A décima praga — morte dos primogênitos — só poupou quem tinha o sangue do cordeiro nos umbrais. O cordeiro pascal é o tipo mais claro de Cristo: 'Cristo, nossa Páscoa, foi sacrificado por nós' (1 Co 5:7)."),
    QuizQuestion(id:186, question:"Qual era o nome da irmã de Moisés que tocou pandeiro após a travessia do Mar Vermelho?", options:["Débora","Miriã","Rute","Ana"], correctIndex:1, explanation:"Miriã, irmã de Moisés, liderou as mulheres em cântico e dança com pandeiro após a milagrosa travessia do Mar Vermelho.", reference:"Êxodo 15:20-21", category:.profetas, propheticMeaning:"O cântico de Miriã é o primeiro cântico registrado na Bíblia em resposta à redenção. Antecipa o cântico de Moisés e do Cordeiro em Apocalipse 15:3 — adoração eterna pela redenção final em Cristo."),
    QuizQuestion(id:187, question:"Em qual monte Deus deu os Dez Mandamentos a Moisés?", options:["Monte Carmelo","Monte Sinai","Monte Nebo","Monte Hermom"], correctIndex:1, explanation:"Deus desceu sobre o Monte Sinai em fogo e trovões e ali entregou a Moisés os Dez Mandamentos gravados em duas tábuas de pedra.", reference:"Êxodo 19:20; 20:1-17", category:.profetas, propheticMeaning:"A lei dada no Sinai era 'pedagogo para conduzir a Cristo' (Gl 3:24). Os Dez Mandamentos revelam o caráter de Deus e a impossibilidade humana de cumpri-los, apontando para a necessidade do Salvador que os cumpriria em nosso lugar."),
    QuizQuestion(id:188, question:"Por quanto tempo Israel perambulou pelo deserto antes de entrar em Canaã?", options:["20 anos","30 anos","40 anos","50 anos"], correctIndex:2, explanation:"Por causa da incredulidade em Cades-Barneia, onde recusaram entrar em Canaã, Israel foi condenado a vagar 40 anos no deserto até a geração incrédula morrer.", reference:"Números 14:33-34", category:.profetas, propheticMeaning:"Os 40 anos no deserto representam o período de provação e disciplina. Paulo usa esse período como advertência para a Igreja: 'Estas coisas nos aconteceram como exemplos... para advertência nossa' (1 Co 10:11)."),
    QuizQuestion(id:189, question:"Quem conduziu Israel para dentro da Terra Prometida após Moisés?", options:["Calebe","Josué","Eleazar","Finéias"], correctIndex:1, explanation:"Josué, fiel espião que havia crido em Deus em Cades-Barneia, foi escolhido por Deus para substituir Moisés e conduzir Israel a Canaã.", reference:"Josué 1:1-3", category:.profetas, propheticMeaning:"O nome Josué em hebraico é Yeshua — o mesmo nome de Jesus em grego. Josué conduzindo Israel à Terra Prometida é tipo de Jesus conduzindo seu povo ao descanso eterno (Hb 4:8-9). A 'Josué maior' é Cristo."),
    QuizQuestion(id:190, question:"Qual foi o primeiro milagre quando Josué conduziu Israel para Canaã?", options:["O sol parou","As muralhas de Jericó caíram","As águas do Jordão se dividiram","Deus enviou granizo sobre os inimigos"], correctIndex:2, explanation:"Quando os sacerdotes com a Arca entraram no Jordão, as águas se dividiram, e todo Israel atravessou em seco, assim como no Mar Vermelho.", reference:"Josué 3:15-17", category:.profetas, propheticMeaning:"A divisão do Jordão espelha o Mar Vermelho — início e fim da jornada no deserto. A Arca (presença de Deus) na frente abre o caminho. Cristo, nossa Arca da aliança, abre o caminho para nossa entrada no descanso eterno."),
    QuizQuestion(id:191, question:"Como as muralhas de Jericó caíram?", options:["Foram derrubadas por aríetes","Caíram por um terremoto","Caíram após Israel marchar ao redor por 7 dias e tocar trombetas no","Um anjo as destruiu"], correctIndex:2, explanation:"Seguindo as instruções de Deus, Israel marchou ao redor de Jericó por 6 dias; no 7º dia marcharam 7 vezes, os sacerdotes tocaram as trombetas, o povo gritou, e as muralhas ruíram.", reference:"Josué 6:15-20", category:.profetas, propheticMeaning:"A queda de Jericó pela obediência de fé (não por força militar) é o padrão do Reino: vitórias espirituais vêm pela obediência à Palavra de Deus, não pela sabedoria humana. O grito de vitória prefigura o clamor na volta de Cristo (1 Ts 4:16)."),
    QuizQuestion(id:192, question:"Quem era Débora na história de Israel?", options:["Uma rainha","Uma profetisa e juíza que liderou Israel à vitória","A esposa do rei Saul","Uma sacerdotisa do templo"], correctIndex:1, explanation:"Débora era profetisa e juíza que governava Israel sob uma palmeira. Ela incentivou Baraque a combater Sísera e cantou o hino de vitória após a batalha.", reference:"Juízes 4:4-9", category:.profetas, propheticMeaning:"Débora liderando Israel numa geração de homens passivos aponta para o Espírito que sopra onde quer (Jo 3:8). Na Nova Aliança, o Espírito é derramado sobre filhos e filhas (At 2:17), quebrando barreiras de gênero no serviço ao Reino."),
    QuizQuestion(id:193, question:"Qual era a fraqueza de Sansão?", options:["O medo da escuridão","Seu cabelo, que continha o segredo de sua força","A sede","A falta de oração"], correctIndex:1, explanation:"A força de Sansão estava ligada ao seu nazireado e ao seu cabelo não cortado. Quando Dalila o cortou enquanto ele dormia, sua força partiu.", reference:"Juízes 16:17-19", category:.profetas, propheticMeaning:"Sansão é um tipo controverso de Cristo: consagrado desde o ventre materno (como Jesus), libertou Israel de inimigos, morreu entre os inimigos destruindo-os (como Cristo na cruz). Sua fraqueza por amor contrasta com a morte voluntária de Jesus."),
    QuizQuestion(id:194, question:"Quem ungiu Davi como rei de Israel?", options:["Natã","Eli","Samuel","Gade"], correctIndex:2, explanation:"O profeta Samuel ungiu Davi com azeite em Belém, diante de seus irmãos, após Deus rejeitar os outros filhos de Jessé.", reference:"1 Samuel 16:13", category:.profetas, propheticMeaning:"Davi ungido por Samuel é tipo de Cristo ungido pelo Espírito Santo no batismo. 'Cristo' e 'Messias' ambos significam 'ungido' — Jesus é o Ungido por excelência, o Filho de Davi prometido para reinar eternamente."),
    QuizQuestion(id:195, question:"Como Davi derrotou o gigante Golias?", options:["Com uma espada","Com uma lança","Com uma pedra numa funda","Com uma armadilha"], correctIndex:2, explanation:"Davi, jovem pastor, enfrentou o gigante Golias com uma funda e cinco pedras. A primeira pedra acertou a testa de Golias, que caiu morto.", reference:"1 Samuel 17:49-50", category:.profetas, propheticMeaning:"Davi vencendo Golias pela fé, não por força ou armadura, é tipo de Cristo vencendo Satanás — não por poder militar mas pela fé e obediência. O 'menor' (Davi/Jesus) derrota o 'grande' (Golias/Satanás) para libertar o povo cativo."),
    QuizQuestion(id:196, question:"Qual foi a grande profecia que Natã fez a Davi sobre sua linhagem?", options:["Que seu templo seria construído por ele","Que o trono de Davi seria estabelecido para sempre e que um","Que Davi viveria 100 anos","Que Israel se tornaria o maior império do mundo"], correctIndex:1, explanation:"Natã profetizou a Davi que Deus estabeleceria o trono de seu descendente para sempre — uma aliança davídica cumprida em Jesus Cristo, filho de Davi.", reference:"2 Samuel 7:12-16", category:.profetas, propheticMeaning:"A aliança davídica (2 Sm 7:16) é central na teologia messiânica. Gabriel citou essa profecia ao anunciar o nascimento de Jesus: 'O Senhor Deus lhe dará o trono de seu pai Davi, e reinará... e o seu reino não terá fim' (Lc 1:32-33)."),
    QuizQuestion(id:197, question:"Quem construiu o primeiro templo em Jerusalém?", options:["Davi","Salomão","Ezequias","Zorobabel"], correctIndex:1, explanation:"Salomão construiu o primeiro templo em Jerusalém no monte Moriá, onde Abraão havia ofertado Isaque, com cedro do Líbano e ouro abundante.", reference:"1 Reis 6:1", category:.profetas, propheticMeaning:"O templo de Salomão é tipo do corpo de Cristo (Jo 2:21) e da Igreja como templo do Espírito Santo (1 Co 3:16). O templo físico era a morada de Deus na terra; Cristo é a morada definitiva de Deus entre os homens (Jo 1:14)."),
    QuizQuestion(id:198, question:"Qual famosa rainha visitou Salomão para testar sua sabedoria?", options:["Rainha de Sabá","Rainha Jezabel","Rainha Ester","Rainha de Tiro"], correctIndex:0, explanation:"A Rainha de Sabá viajou uma longa distância para testar Salomão com perguntas difíceis e ficou deslumbrada com sua sabedoria e riqueza.", reference:"1 Reis 10:1-10", category:.profetas, propheticMeaning:"Jesus usou a Rainha de Sabá para condenar a geração que não creu nele: 'A rainha do Sul se levantará no julgamento... pois ela veio dos fins da terra para ouvir a sabedoria de Salomão; e eis aqui mais do que Salomão' (Mt 12:42)."),
    QuizQuestion(id:199, question:"Qual profeta desafiou os 450 profetas de Baal no Monte Carmelo?", options:["Eliseu","Isaías","Elias","Jeremias"], correctIndex:2, explanation:"Elias desafiou os 450 profetas de Baal e os 400 profetas de Aser no Monte Carmelo. O Deus que respondesse com fogo seria o verdadeiro Deus. O fogo do Senhor desceu e consumiu o sacrifício de Elias.", reference:"1 Reis 18:20-39", category:.profetas, propheticMeaning:"O fogo do Senhor no Carmelo demonstrou que YHWH, não Baal, é o Deus vivo. Este fogo é tipo do Espírito Santo que desceu em Pentecostes, confirmando que Jesus é o Senhor — consumindo o sacrifício vivo que oferecemos a Deus (Rm 12:1)."),
    QuizQuestion(id:200, question:"Quem foi Isaías e qual é sua maior profecia messiânica?", options:["Um rei de Israel que escreveu sobre a criação","Um profeta que profetizou 'Uma virgem conceberá e dará à luz um filho","Um sacerdote que reformou o templo","Um profeta menor que falou apenas sobre Israel"], correctIndex:1, explanation:"Isaías é o maior profeta messiânico do AT. Em Isaías 7:14 profetizou o nascimento virginal do Messias, cumprido em Jesus conforme Mateus 1:22-23.", reference:"Isaías 7:14; Mateus 1:22-23", category:.profetas, propheticMeaning:"Isaías 7:14 é uma das mais precisas profecias do AT: uma virgem (almah) concebendo e dando à luz um filho chamado Emanuel ('Deus conosco') — cumprido literalmente em Maria, José e Jesus de Belém, 700 anos depois."),
    QuizQuestion(id:201, question:"O que descreve Isaías 53?", options:["A glória do Messias reinando","O sofrimento e morte substitutiva do Servo do Senhor","A criação do mundo","O juízo de Babilônia"], correctIndex:1, explanation:"Isaías 53 descreve o Servo Sofredor: desprezado, rejeitado, carregando as nossas enfermidades, ferido por nossas transgressões, e pela sua ferida somos curados.", reference:"Isaías 53:3-6", category:.profetas, propheticMeaning:"Isaías 53 é a mais detalhada profecia da paixão de Cristo, escrita 700 anos antes. Cada versículo encontra cumprimento na vida e morte de Jesus — rejeitado (v.3), sofredor (v.4), traspassado (v.5), e sepultado com ricos (v.9)."),
    QuizQuestion(id:202, question:"O que profetizou Jeremias sobre uma nova aliança?", options:["Que Israel teria um rei eterno","Que Deus faria nova aliança escrevendo sua lei no coração","Que o templo seria destruído e reconstruído","Que Babilônia seria destruída definitivamente"], correctIndex:1, explanation:"Jeremias 31:31-34 profetizou a nova aliança: não como a do Sinai, mas escrita no coração, com perdão total dos pecados e conhecimento direto de Deus.", reference:"Jeremias 31:31-34", category:.profetas, propheticMeaning:"A nova aliança de Jeremias é explicitamente citada em Hebreus 8:8-12 como cumprida em Cristo. Na Ceia do Senhor, Jesus disse 'Este cálice é a nova aliança no meu sangue' (Lc 22:20) — inaugurando o que Jeremias havia profetizado."),
    QuizQuestion(id:203, question:"Qual profeta teve a visão do vale de ossos secos que voltaram à vida?", options:["Isaías","Jeremias","Ezequiel","Daniel"], correctIndex:2, explanation:"Ezequiel teve a visão do vale cheio de ossos secos que, ao sopro do Espírito, cobriram-se de carne e se tornaram um exército imenso, simbolizando a restauração de Israel.", reference:"Ezequiel 37:1-10", category:.profetas, propheticMeaning:"A visão dos ossos secos (Ez 37) profetiza a ressurreição espiritual de Israel e também a ressurreição corporal dos mortos. O Espírito que deu vida aos ossos é o mesmo que ressuscitou Cristo e vivirá em nossos corpos mortais (Rm 8:11)."),
    QuizQuestion(id:204, question:"Qual profecia de Miquéias se cumpriu no nascimento de Jesus?", options:["Que nasceria de uma virgem","Que Belém seria o lugar de nascimento do Governador de Israel","Que fugiriam para o Egito","Que seria chamado de Nazareno"], correctIndex:1, explanation:"Miquéias 5:2 profetizou: 'Tu, Belém Efrata... de ti me sairá aquele que há de ser Soberano em Israel.' Os sumo-sacerdotes citaram essa profecia aos Magos.", reference:"Miquéias 5:2; Mateus 2:6", category:.profetas, propheticMeaning:"Miquéias 5:2 é uma das profecias mais precisas do AT: identificando não apenas a pessoa do Messias mas a cidade exata de seu nascimento — Belém Efrata, distinguida de outra Belém. O cumprimento em Jesus é preciso e irrefutável."),
    QuizQuestion(id:205, question:"Daniel foi jogado na cova dos leões por qual razão?", options:["Por conspirar contra o rei","Por se recusar a parar de orar a Deus três vezes por dia","Por revelar os sonhos do rei","Por profetizar contra Babilônia"], correctIndex:1, explanation:"Invejosos de Daniel, os sátrapas enganaram o rei Dario para proibir orar a qualquer deus que não fosse o rei por 30 dias. Daniel continuou orando e foi jogado aos leões.", reference:"Daniel 6:10-16", category:.profetas, propheticMeaning:"Daniel preservado na cova dos leões é tipo de Cristo ressurreto do sepulcro. O rei selou a cova (cf. o sepulcro de Jesus), mas Deus abriu o caminho. A fidelidade de Daniel mesmo sob ameaça de morte é modelo da martirologia cristã."),
    QuizQuestion(id:206, question:"Qual profecia de Daniel sobre 'o Filho do Homem' é citada por Jesus?", options:["A estátua dos reinos","As 70 semanas","O Filho do Homem vindo nas nuvens com poder e glória","O quarto reino de ferro"], correctIndex:2, explanation:"Daniel 7:13-14 visiona 'alguém como o Filho do Homem' vindo nas nuvens recebendo domínio eterno sobre todos os povos. Jesus usou exatamente esse título para si mesmo.", reference:"Daniel 7:13-14; Marcos 14:62", category:.profetas, propheticMeaning:"Jesus declarando-se o 'Filho do Homem' de Daniel 7 foi o que levou o sumo-sacerdote a acusá-lo de blasfêmia (Mc 14:63-64). Cristo confirmou: ele é o Rei eterno das nações, que virá nas nuvens na consumação dos tempos."),
    QuizQuestion(id:207, question:"O que profetizou Zacarias sobre o Messias entrando em Jerusalém?", options:["Que entraria em carro de guerra","Que entraria a pé, sozinho","Que entraria humilde, montado num jumento","Que entraria no templo com fogo"], correctIndex:2, explanation:"Zacarias 9:9: 'Regozijai-vos, filha de Sião... eis que o teu Rei vem a ti, justo e salvador, humilde e montado num jumento.' Cumprido na entrada triunfal de Jesus.", reference:"Zacarias 9:9; Mateus 21:4-5", category:.profetas, propheticMeaning:"Zacarias 9:9 especifica que o Rei-Messias viria humilde, num jumento (símbolo de paz), não num cavalo de guerra. Jesus cumpriu isso literalmente, declarando ser o Rei que vem em paz, não para guerra — desta vez."),
    QuizQuestion(id:208, question:"Qual profecia de Zacarias fala do preço de trinta moedas de prata?", options:["Zacarias 9:9","Zacarias 11:12-13","Zacarias 12:10","Zacarias 14:4"], correctIndex:1, explanation:"Zacarias 11:12-13 profetizou 500 anos antes que o pastor seria avaliado em 30 moedas de prata, jogadas para o oleiro no templo — cumprido com Judas.", reference:"Zacarias 11:12-13; Mateus 27:9", category:.profetas, propheticMeaning:"Cada detalhe foi cumprido: o preço de 30 moedas (preço de um escravo, Êx 21:32 — Jesus se fez escravo, Fp 2:7), jogado no templo, destinado ao oleiro para comprar o campo do oleiro. Precisão profética sobrenatural."),
    QuizQuestion(id:209, question:"O que profetizou Zacarias sobre o Messias que seria traspassado?", options:["Que seus pés poucariam no Monte das Oliveiras","Que olhariam para aquele que traspassaram e o pranto seria grande","Que ele destruiria os exércitos inimigos","Que o templo seria destruído"], correctIndex:1, explanation:"Zacarias 12:10: 'Derramarei sobre a casa de Davi... o espírito de graça e de súplicas; e olharão para mim, aquele que traspassaram, e o pranteaEarão.'", reference:"Zacarias 12:10; João 19:37", category:.profetas, propheticMeaning:"João 19:37 cita Zacarias 12:10 ao descrever a lança que traspassou o lado de Jesus. A profecia olha adiante para o fim dos tempos quando Israel reconhecerá seu Messias — o cumprimento final da profecia ainda está por vir."),
    QuizQuestion(id:210, question:"Qual é a última profecia do AT em Malaquias sobre o precursor do Messias?", options:["Que um profeta como Moisés viria","'Eis que enviarei o meu mensageiro... e o Senhor a quem buscais virá","Que o templo seria reconstruído","Que Israel retornaria do exílio"], correctIndex:1, explanation:"Malaquias 3:1 profetizou: 'Eis que enviarei o meu mensageiro que preparará o caminho diante de mim.' Jesus identificou João Batista como cumprimento desta profecia.", reference:"Malaquias 3:1; Mateus 11:10", category:.profetas, propheticMeaning:"Malaquias 3:1 é a última profecia do AT antes de 400 anos de silêncio. O 'mensageiro' é João Batista; 'o Senhor a quem buscais' é Jesus. Deus encerrou o AT com uma promessa e a abriu com seu cumprimento em Cristo."),
    QuizQuestion(id:211, question:"O que aconteceu quando o profeta Elias fugiu de Jezabel para o monte Horebe?", options:["Deus lhe apareceu em fogo e vendaval","Deus veio numa voz delicada e mansa após vento, terremoto e fogo","Deus lhe mandou 40.000 exércitos","Deus ordenou que construísse um templo"], correctIndex:1, explanation:"Deus não estava no vento forte, nem no terremoto, nem no fogo — mas numa voz delicada e mansa. Ali encorajou Elias, informando que ainda havia 7.000 que não tinham adorado Baal.", reference:"1 Reis 19:12", category:.profetas, propheticMeaning:"A voz delicada de Deus a Elias mostra que Deus frequentemente fala no silêncio, não em espetáculos. É tipo do ministério do Espírito Santo que gentilmente guia e consola — contrastando com o estilo espetacular que Elias esperava."),
    QuizQuestion(id:212, question:"Qual profeta comeu um rolo de livro em visão e achou doce como mel?", options:["Isaías","Jeremias","Ezequiel","Zacarias"], correctIndex:2, explanation:"Em visão, Ezequiel comeu um rolo de livro coberto de palavras de lamentação e gemido. Ao comê-lo, achou doce como mel na boca, mas amargo no ventre.", reference:"Ezequiel 3:1-3", category:.profetas, propheticMeaning:"O rolo doce mas amargo ilustra a Palavra de Deus: o evangelho é 'suave para o paladar' do crente (Sl 119:103), mas traz mensagem de juízo para os ímpios. João em Apocalipse 10 repete a mesma experiência, conectando os dois profetas."),
    QuizQuestion(id:213, question:"Qual profeta foi chamado a anunciar julgamento mas também a comprar um campo durante o cerco de Jerusalém como sinal de esperança?", options:["Isaías","Jeremias","Ezequiel","Amós"], correctIndex:1, explanation:"Jeremias comprou o campo de Hanameel em Anatote durante o cerco babilônico como sinal profético: 'Casas, campos e vinhas serão comprados nesta terra', anunciando a restauração futura.", reference:"Jeremias 32:6-15", category:.profetas, propheticMeaning:"Jeremias comprando campo durante o cerco é ato de fé radical na promessa de restauração — tipo de quem investe no Reino de Deus quando o mundo parece desabar. A compra do campo prefigura a redenção e restauração em Cristo."),
    QuizQuestion(id:214, question:"O que significava a profecia de Oséias de amar sua esposa infiel como imagem do amor de Deus por Israel?", options:["Que Deus abandonaria Israel","Que Deus amaria Israel apesar de sua idolatria, chamando-a de volta","Que Oséias devia punir sua esposa","Que o casamento não era importante"], correctIndex:1, explanation:"Deus ordenou a Oséias que amasse sua esposa Gomer apesar da infidelidade, como imagem do amor inabalável de Deus por Israel que havia se prostituído com ídolos.", reference:"Oséias 3:1", category:.profetas, propheticMeaning:"O amor redentor de Oséias por Gomer é um dos mais belos tipos do amor de Cristo pela Igreja — que era pecadora e infiel, mas foi amada, redimida e restaurada pelo sangue de Cristo. O evangelho é uma história de amor redentor."),
    QuizQuestion(id:215, question:"Qual é a famosa promessa de Joel sobre o derramamento do Espírito?", options:["Que o Espírito viria apenas para os profetas","'Derramarei do meu Espírito sobre toda a carne","Que o Espírito guiaria apenas Israel","Que o Espírito viria somente no fim dos tempos"], correctIndex:1, explanation:"Joel 2:28-29 profetizou: 'Depois disto, derramarei do meu Espírito sobre toda a carne; vossos filhos e vossas filhas profetizarão... sobre os servos e as servas, naqueles dias, derramarei o meu Espírito.'", reference:"Joel 2:28-29; Atos 2:16-17", category:.profetas, propheticMeaning:"Pedro citou Joel 2 no Pentecostes dizendo 'Isto é o que foi dito pelo profeta Joel.' O derramamento do Espírito sobre 'toda a carne' é o cumprimento em Cristo — a democratização da presença divina acessível a todos os crentes."),
    QuizQuestion(id:216, question:"Qual profeta denunciou o pecado de Israel usando a imagem de uma plomada e um cesto de fruta madura?", options:["Isaías","Jeremias","Amós","Miquéias"], correctIndex:2, explanation:"Amós recebeu visões de uma plomada (Amós 7:7-8) — Deus medindo Israel pelo padrão da justiça — e de um cesto de frutas maduras (Amós 8:1-2), simbolizando que Israel estava maduro para o juízo.", reference:"Amós 7:7-8; 8:1-2", category:.profetas, propheticMeaning:"A plomada de Deus é a norma da justiça — que só Cristo cumpriu perfeitamente. O cesto de frutas maduras (verão = fim em hebraico) anuncia o juízo, que em Cristo se torna graça para os que creem antes que o julgamento venha."),
    QuizQuestion(id:217, question:"O que proclamou o profeta Habacuque que se tornou o versículo chave da Reforma?", options:["'Deus é nosso refúgio'","'O justo viverá pela sua fé'","'Conhecereis a verdade e a verdade vos libertará'","'A salvação é do Senhor'"], correctIndex:1, explanation:"Habacuque 2:4: 'O justo viverá pela sua fé.' Este versículo é citado três vezes no NT (Rm 1:17; Gl 3:11; Hb 10:38) e foi o versículo que transformou Lutero.", reference:"Habacuque 2:4; Romanos 1:17", category:.profetas, propheticMeaning:"'O justo viverá pela fé' é a pedra angular da salvação bíblica. Paulo em Romanos mostra que Abraão, Davi e todos os salvos do AT foram justificados pela fé — o mesmo princípio que salva os crentes em Cristo Jesus hoje."),
    QuizQuestion(id:218, question:"Qual profeta anunciou 'Quanto amor manifesto a ti, ó Israel! Mas tu me substituíste por ídolos'?", options:["Isaías","Oséias","Jeremias","Amós"], correctIndex:1, explanation:"Oséias foi o profeta do amor de Deus traído — sua mensagem central é que Israel abandonou o amor do Senhor pelos ídolos, mas Deus continua os amando e chamando ao retorno.", reference:"Oséias 11:1-4", category:.profetas, propheticMeaning:"Oséias 11:1 — 'Do Egito chamei meu filho' — é citado por Mateus 2:15 referindo-se a Jesus retornando do Egito. O profeta falava de Israel historicamente; Mateus vê o cumprimento tipológico: Jesus é o verdadeiro Israel."),
    QuizQuestion(id:219, question:"Qual profecia de Isaías 9:6 descreve os títulos do Messias?", options:["'Servo humilde e manso'","'Maravilhoso Conselheiro, Deus Forte, Pai da Eternidade","'Rei de Israel e Profeta das nações'","'Pastor dos pastores e Sacerdote eterno'"], correctIndex:1, explanation:"Isaías 9:6: 'Porque um menino nos nasceu, um filho nos foi dado... e o seu nome será: Maravilhoso Conselheiro, Deus Forte, Pai da Eternidade, Príncipe da Paz.'", reference:"Isaías 9:6", category:.profetas, propheticMeaning:"Os quatro títulos de Isaías 9:6 revelam as quatro dimensões de Cristo: Maravilhoso Conselheiro (profeta), Deus Forte (divindade), Pai da Eternidade (eterno), Príncipe da Paz (rei de paz). Cada um confirma sua identidade messiânica e divina."),
    QuizQuestion(id:220, question:"O que aconteceu com o profeta Jeremias por causa de sua mensagem impopular?", options:["Foi honrado como herói nacional","Foi jogado em uma cisterna e perseguido","Foi levado ao céu como Elias","Foi feito sumo-sacerdote"], correctIndex:1, explanation:"Jeremias sofreu grande perseguição: foi açoitado, preso, e jogado numa cisterna de lama pelos príncipes que consideravam sua mensagem traidora durante o cerco babilônico.", reference:"Jeremias 38:6", category:.profetas, propheticMeaning:"Jeremias no poço de lama, salvo por um etíope, é tipo de Cristo sepultado e ressurreto. O profeta 'da cisterna' prefigura o Servo Sofredor que vai às profundezas (morte) e é resgatado por Deus para cumprir sua missão."),
    QuizQuestion(id:221, question:"Qual é a profecia de Isaías 40:3 que João Batista cumpriu?", options:["'Uma virgem conceberá'","'Voz do que clama no deserto: preparai o caminho do Senhor'","'Eis o meu servo a quem elegi'","'Porque um menino nos nasceu'"], correctIndex:1, explanation:"Isaías 40:3: 'Voz do que clama no deserto: Preparai o caminho do Senhor; endireitai no deserto uma estrada para o nosso Deus.' João Batista identificou-se como cumprimento desta profecia.", reference:"Isaías 40:3; João 1:23", category:.profetas, propheticMeaning:"João Batista preparando o caminho para Jesus é o cumprimento de Isaías 40:3. O 'deserto' era tanto físico (João pregou no deserto) quanto espiritual — os corações áridos dos israelitas precisavam ser preparados para receber o Messias."),
    QuizQuestion(id:222, question:"Quem foi o profeta que Deus chamou enquanto ainda era jovem, dizendo 'Antes que saísse do ventre, eu te santifiquei'?", options:["Isaías","Jeremias","Ezequiel","Amós"], correctIndex:1, explanation:"Deus disse a Jeremias: 'Antes que eu te formasse no ventre te conheci, e antes que saísses da madre te santifiquei; às nações te dei por profeta.' Jeremias sentiu-se jovem demais, mas Deus o comissionou.", reference:"Jeremias 1:5", category:.profetas, propheticMeaning:"'Antes que te formasse no ventre te conheci' revela a eleição soberana de Deus antes do nascimento, aplicada também a cada crente (Ef 1:4). Paulo usa linguagem idêntica para seu próprio chamado (Gl 1:15), conectando-o à tradição profética."),
    QuizQuestion(id:223, question:"O que profetizou Isaías 53:5?", options:["'Ele será exaltado e levantado'","'Mas ele foi traspassado pelas nossas transgressões... e pelo seu...","'Eis o meu servo a quem elegi'","'O Espírito do Senhor está sobre mim'"], correctIndex:1, explanation:"Isaías 53:5: 'Mas ele foi traspassado pelas nossas transgressões e moído pelas nossas iniquidades; o castigo que nos traz a paz estava sobre ele, e pelo seu ferimento fomos sarados.'", reference:"Isaías 53:5", category:.profetas, propheticMeaning:"Isaías 53:5 é a mais clara proclamação da expiação substitutiva do AT: o Servo leva nossas transgressões, iniquidades e recebe o castigo que produze nossa paz. Pedro cita diretamente (1 Pe 2:24) referindo-se à crucificação de Jesus."),
    QuizQuestion(id:224, question:"Qual profeta disse 'O Espírito do Senhor Deus está sobre mim' (citado por Jesus em Nazaré)?", options:["Moisés","Jeremias","Isaías","Ezequiel"], correctIndex:2, explanation:"Isaías 61:1-2 começa: 'O Espírito do Senhor Deus está sobre mim, porque me ungiu o Senhor para proclamar boas novas aos pobres.' Jesus leu este texto em Nazaré e disse que foi cumprido naquele dia.", reference:"Isaías 61:1-2; Lucas 4:18-21", category:.profetas, propheticMeaning:"Jesus identificando-se como cumprimento de Isaías 61 é sua declaração messiânica pública. O 'ano aceitável do Senhor' é a era da graça iniciada por Cristo — e ele parou antes de 'o dia da vingança', que pertence à segunda vinda."),
    QuizQuestion(id:225, question:"Qual profeta ministrou em grande parte no tempo do rei Ezequias, diante da ameaça assíria?", options:["Jeremias","Ezequiel","Isaías","Daniel"], correctIndex:2, explanation:"Isaías ministrou durante os reinados de Uzias, Jotão, Acaz e Ezequias. Foi instrumental no período da ameaça assíria, quando encorajou Ezequias a confiar em Deus.", reference:"Isaías 1:1; 37:1-7", category:.profetas, propheticMeaning:"Isaías aconselhando Ezequias a confiar em Deus diante dos assírios é tipo de Cristo como conselheiro que nos encoraja quando as 'potências' nos ameaçam. Ezequias orou e Deus livrou — padrão eterno para o povo de Deus."),
    QuizQuestion(id:226, question:"Qual profecia do Salmo 22 descreve a crucificação de Cristo com 1000 anos de antecedência?", options:["'O Senhor é meu pastor'","'Mãos e pés me traspassaram","'O Senhor te guardará'","'Cantarei ao Senhor um cântico novo'"], correctIndex:1, explanation:"O Salmo 22:16-18 descreve mãos e pés traspassados, ossos contados, vestes divididas e sortes lançadas — detalhes da crucificação de Jesus cumpridos literalmente, sem que Davi soubesse o que estava profetizando.", reference:"Salmos 22:16-18; João 19:23-24", category:.profetas, propheticMeaning:"O Salmo 22 foi escrito por Davi que nunca foi crucificado e viveu quando a crucificação nem existia como método de execução. Somente inspiração divina explica a precisão profética: cada detalhe se cumpriu em Cristo na cruz."),
    QuizQuestion(id:227, question:"O que profetizou Daniel com as '70 semanas'?", options:["Que o exílio duraria 70 anos","Um cronograma profético sobre o Messias e o destino de Jerusalém","Que 70 reis governariam Israel","Que o templo seria reconstruído em 70 dias"], correctIndex:1, explanation:"As 70 semanas de Daniel 9 é um dos mais precisos cronogramas proféticos da Bíblia, traçando o tempo da vinda do Messias e a destruição de Jerusalém.", reference:"Daniel 9:24-27", category:.profetas, propheticMeaning:"As 70 semanas de Daniel (Daniel 9:24-27) foram calculadas por estudiosos apontando ao tempo de Jesus — do decreto de reconstrução (445 a.C.) até a entrada triunfal em Jerusalém. Esta profecia é uma das provas mais precisas de que Jesus é o Messias prometido."),
    QuizQuestion(id:228, question:"Qual profeta viveu dentro de um boi de bronze e viu a glória de Deus na tempestade?", options:["Isaías","Jeremias","Ezequiel","Daniel"], correctIndex:2, explanation:"Ezequiel teve uma visão extraordinária: uma tempestade com fogo, quatro criaturas viventes, rodas dentro de rodas e o trono de Deus acima de tudo — a visão da glória (kavod) do Senhor.", reference:"Ezequiel 1:4-28", category:.profetas, propheticMeaning:"A visão da glória de Ezequiel 1 é uma teofania — manifestação da presença divina. As quatro criaturas viventes reaparecem em Apocalipse 4:6-8 ao redor do trono de Deus, conectando a visão de Ezequiel com a adoração eterna da consumação."),
    QuizQuestion(id:229, question:"Qual profeta anunciou o famoso versículo 'Nação não levantará espada contra nação, nem aprenderão mais a guerra'?", options:["Miquéias","Isaías","Jeremias","Amós"], correctIndex:1, explanation:"Isaías 2:4 e Miquéias 4:3 têm texto idêntico sobre o reino messiânico de paz: 'Transformarão as suas espadas em arados... nação não levantará espada contra nação.'", reference:"Isaías 2:4; Miquéias 4:3", category:.profetas, propheticMeaning:"A paz universal profetizada por Isaías e Miquéias se cumprirá plenamente no reino milenar de Cristo. Enquanto isso, o evangelho é 'as boas novas de paz' (Ef 6:15) que Cristo trouxe — a paz com Deus que precede a paz entre nações."),
    QuizQuestion(id:230, question:"Qual profeta chamou Israel de volta após o exílio com as palavras 'Consolai, consolai o meu povo'?", options:["Jeremias","Ezequiel","Isaías","Zacarias"], correctIndex:2, explanation:"Isaías 40 começa com 'Consolai, consolai o meu povo, diz o vosso Deus. Falai ao coração de Jerusalém' — o início da seção conhecida como 'Deutero-Isaías' ou Isaías do Consolador.", reference:"Isaías 40:1-2", category:.profetas, propheticMeaning:"'Consolai' (nakhamu) abre o livro do consolador — Isaías 40-66 é o livro do evangelho no AT. O Espírito Santo é chamado 'Consolador' (parakletos) em João 14:16 — conectando a promessa de consolo à pessoa do Espírito enviado por Cristo."),
]
